# ── Colour helpers ────────────────────────────────────────────────────────────

class C:
    _t = sys.stdout.isatty()
    BOLD   = "\033[1m"  if _t else ""; CYAN   = "\033[36m" if _t else ""
    GREEN  = "\033[32m" if _t else ""; YELLOW = "\033[33m" if _t else ""
    RED    = "\033[31m" if _t else ""; DIM    = "\033[2m"  if _t else ""
    RESET  = "\033[0m"  if _t else ""

_ANSI_RE = re.compile(r"\033\[[0-9;]*m")


# ── Logging ───────────────────────────────────────────────────────────────────

_log_file: IO | None = None   # set by main() after arg parsing
_event_counter: int = 1       # incremented by get_event_counter() on each event


def get_event_counter() -> int:
    """Return the current event counter value then increment it."""
    global _event_counter
    n = _event_counter
    _event_counter += 1
    return n


def log(text: str = "", *, to_stderr: bool = False) -> None:
    """
    Print text to stdout (or stderr) and, if a log file is open, also write
    an ANSI-stripped copy to the log file.
    """
    dest = sys.stderr if to_stderr else sys.stdout
    print(text, file=dest)
    if _log_file is not None:
        clean = _ANSI_RE.sub("", text)
        print(clean, file=_log_file)


# ── evdev constants ───────────────────────────────────────────────────────────

EV_SYN = 0
EV_KEY = 1
EV_REL = 2
EV_ABS = 3

BTN_LEFT   = 0x110
BTN_RIGHT  = 0x111
BTN_MIDDLE = 0x112

KEY_RELEASED = 0
KEY_PRESSED  = 1
KEY_REPEATED = 2

REL_X = 0
REL_Y = 1
ABS_X = 0
ABS_Y = 1


# ── Keyboard keycode tables ───────────────────────────────────────────────────

_MODIFIER_CODES: dict[int, str] = {
    29:  "CTRL",   97:  "CTRL",
    42:  "SHIFT",  54:  "SHIFT",
    56:  "ALT",    100: "ALT",
    125: "META",   126: "META",
}

_FLUSH_CODES: set[int] = {28, 1}   # ENTER, ESC

_SPECIAL_KEYS: dict[int, str] = {
    28:  "ENTER",
    1:   "ESC",
    15:  "TAB",
    14:  "BACKSPACE",
    111: "DELETE",
    110: "INSERT",
    103: "UP",
    108: "DOWN",
    105: "LEFT",
    106: "RIGHT",
    104: "PGUP",
    109: "PGDN",
    102: "HOME",
    107: "END",
    59:  "F1",   60: "F2",   61: "F3",   62:  "F4",
    63:  "F5",   64: "F6",   65: "F7",   66:  "F8",
    67:  "F9",   68: "F10",  87: "F11",  88:  "F12",
    99:  "PRTSC",
}

_PRINTABLE_KEYS: dict[int, tuple[str, str]] = {
    30: ("a","A"), 48: ("b","B"), 46: ("c","C"), 32: ("d","D"),
    18: ("e","E"), 33: ("f","F"), 34: ("g","G"), 35: ("h","H"),
    23: ("i","I"), 36: ("j","J"), 37: ("k","K"), 38: ("l","L"),
    50: ("m","M"), 49: ("n","N"), 24: ("o","O"), 25: ("p","P"),
    16: ("q","Q"), 19: ("r","R"), 31: ("s","S"), 20: ("t","T"),
    22: ("u","U"), 47: ("v","V"), 17: ("w","W"), 45: ("x","X"),
    21: ("y","Y"), 44: ("z","Z"),
    2:  ("1","!"), 3:  ("2","@"), 4:  ("3","#"), 5:  ("4","$"),
    6:  ("5","%"), 7:  ("6","^"), 8:  ("7","&"), 9:  ("8","*"),
    10: ("9","("), 11: ("0",")"),
    12: ("-","_"), 13: ("=","+"), 26: ("[","{"), 27: ("]","}"),
    43: ("\\","|"), 39: (";",":"), 40: ("'",'"'), 41: ("`","~"),
    51: (",","<"), 52: (".",">"), 53: ("/","?"),
    57: (" "," "),
}


# ── Keyboard buffer ───────────────────────────────────────────────────────────

class KeyboardBuffer:
    """
    Accumulates keypresses as DSL segments and flushes them as a single
    input_actions-compatible line on ENTER, ESC, or window change.
    """

    def __init__(self) -> None:
        self._segments: list[str] = []
        self._held_modifiers: set[str] = set()

    def key_event(self, keycode: int, state: int) -> bool:
        """
        Process one EV_KEY event.
        Returns True if the buffer should be flushed (ENTER or ESC pressed).
        Auto-repeat events (state=KEY_REPEATED) are ignored.
        """
        if state == KEY_REPEATED:
            return False

        if keycode in _MODIFIER_CODES:
            mod_name = _MODIFIER_CODES[keycode]
            if state == KEY_PRESSED:
                self._held_modifiers.add(mod_name)
            else:
                self._held_modifiers.discard(mod_name)
            return False

        if state != KEY_PRESSED:
            return False

        if keycode in _FLUSH_CODES:
            self._segments.append(f"{{{_SPECIAL_KEYS[keycode]}}}")
            return True

        mods = self._held_modifiers.copy()

        if keycode in _PRINTABLE_KEYS:
            unshifted, shifted = _PRINTABLE_KEYS[keycode]
            shift_held = "SHIFT" in mods
            if not mods or (shift_held and len(mods) == 1):
                self._segments.append(shifted if shift_held else unshifted)
                return False
            char_name = shifted.upper() if shift_held else unshifted.upper()
            non_shift = sorted(mods - {"SHIFT"})
            if non_shift:
                self._segments.append(
                    "{" + "+".join(non_shift) + "+" + char_name + "}"
                )
            else:
                self._segments.append(f"{{{char_name}}}")
            return False

        if keycode in _SPECIAL_KEYS:
            name = _SPECIAL_KEYS[keycode]
            if mods:
                self._segments.append(
                    "{" + "+".join(sorted(mods)) + "+" + name + "}"
                )
            else:
                self._segments.append(f"{{{name}}}")
            return False

        # Unknown keycode
        if mods:
            self._segments.append(
                "{" + "+".join(sorted(mods)) + f"+KEY{keycode}" + "}"
            )
        else:
            self._segments.append(f"{{KEY{keycode}}}")
        return False

    def is_empty(self) -> bool:
        return not self._segments

    def flush(
        self,
        kwin_info: dict | None,
        id_index:  dict[str, str],
        no_dsl:    bool,
    ) -> None:
        """Emit accumulated buffer as comment + DSL line and reset."""
        if not self._segments:
            return

        joined = "".join(self._segments).strip()
        self._segments.clear()
        self._held_modifiers.clear()

        if not joined:
            return

        if kwin_info is None:
            log(f"{C.DIM}# {get_event_counter()} (KWin query failed)  |  keyboard{C.RESET}")
        else:
            active_id    = kwin_info.get("active_id", "")
            caption      = kwin_info.get("caption", "")
            app_alias    = id_index.get(active_id, "") or active_id[:12] or "(unknown)"
            caption_part = f'  |  "{caption}"' if caption else ""
            log(
                f"{C.CYAN}# {get_event_counter()} {app_alias}{caption_part}  |  "
                f"keyboard{C.RESET}"
            )

        if not no_dsl:
            log(f"{C.GREEN}{joined}{C.RESET}")
        log()

    def reset(self) -> None:
        self._segments.clear()
        self._held_modifiers.clear()


# ── KWin query helper ─────────────────────────────────────────────────────────

class KWinMonitor:
    """Keeps a KWinSession open and provides per-event queries."""

    def __init__(self, verbose: bool = False) -> None:
        self._session: KWinSession | None = None
        self._verbose = verbose
        self._lock    = threading.Lock()

    def open(self) -> None:
        self._session = KWinSession(verbose=self._verbose)
        self._session.open()

    def close(self) -> None:
        if self._session:
            try:
                self._session.close()
            except Exception:
                pass
            self._session = None

    def query_click(self) -> dict | None:
        if not self._session:
            return None
        try:
            with self._lock:
                info      = self._session.desktops.active_window_and_cursor()
                active_id = info.get("active_id", "")
                if not active_id:
                    return {
                        "active_id": "", "caption": "",
                        "win_x": 0, "win_y": 0,
                        "cursor_x": info.get("cursor_x", 0),
                        "cursor_y": info.get("cursor_y", 0),
                    }
                geom = self._session.windows.get_screen_geometry(active_id)
                return {
                    "active_id": active_id,
                    "caption":   info.get("caption", ""),
                    "win_x":     geom.get("win_x", 0),
                    "win_y":     geom.get("win_y", 0),
                    "cursor_x":  info.get("cursor_x", 0),
                    "cursor_y":  info.get("cursor_y", 0),
                }
        except Exception as exc:
            if self._verbose:
                log(f"{C.YELLOW}[WARN ] KWin query failed: {exc}{C.RESET}",
                    to_stderr=True)
            return None


# ── Pointer tracker ───────────────────────────────────────────────────────────

class PointerTracker:
    def __init__(self) -> None:
        self.x = 0; self.y = 0; self._has_abs = False

    def feed(self, event_type: int, code: int, value: int) -> None:
        if event_type == EV_REL:
            if code == REL_X: self.x += value
            elif code == REL_Y: self.y += value
        elif event_type == EV_ABS:
            if code == ABS_X: self.x = value; self._has_abs = True
            elif code == ABS_Y: self.y = value; self._has_abs = True

    def seed(self, x: int, y: int) -> None:
        if not self._has_abs:
            self.x = x; self.y = y


# ── Window identity index ─────────────────────────────────────────────────────

def build_id_index(session_state: SessionState,
                   snapshot: LayoutSnapshot | None) -> dict[str, str]:
    index: dict[str, str] = {}
    for entry in session_state.all_entries():
        bare = entry.internal_id.strip("{}")
        if bare:
            index[bare] = entry.app_alias or entry.resource_class
    return index


# ── Click logger ──────────────────────────────────────────────────────────────

def log_click(button: int, abs_x: int, abs_y: int,
              kwin_info: dict | None, id_index: dict[str, str],
              no_dsl: bool) -> None:
    if button == BTN_LEFT:    dsl_prefix = "WCLICK"
    elif button == BTN_RIGHT: dsl_prefix = "WRCLICK"
    else:                     dsl_prefix = "MCLICK"

    if kwin_info is None:
        log(f"{C.DIM}# {get_event_counter()} abs({abs_x}, {abs_y})  |  (KWin query failed){C.RESET}")
        return

    active_id    = kwin_info.get("active_id", "")
    win_x        = kwin_info.get("win_x", 0)
    win_y        = kwin_info.get("win_y", 0)
    caption      = kwin_info.get("caption", "")
    app_alias    = id_index.get(active_id, "") or active_id[:12] or "(unknown)"
    rel_x        = abs_x - win_x
    rel_y        = abs_y - win_y
    caption_part = f'  |  "{caption}"' if caption else ""

    log(f"{C.CYAN}# {get_event_counter()} {app_alias}{caption_part}  |  "
        f"abs({abs_x}, {abs_y})  |  rel({rel_x}, {rel_y}){C.RESET}")

    if not no_dsl and button in (BTN_LEFT, BTN_RIGHT):
        log(f"{C.GREEN}{{{dsl_prefix} {rel_x}, {rel_y}}}{C.RESET}")
    elif not no_dsl and button == BTN_MIDDLE:
        log(f"{C.GREEN}{{{dsl_prefix}}}{C.RESET}")
    log()


def log_drag(abs_x1: int, abs_y1: int, abs_x2: int, abs_y2: int,
             kwin_info: dict | None, id_index: dict[str, str],
             no_dsl: bool) -> None:
    """Emit a comment + {WDRAG} DSL token for a left-button drag."""
    if kwin_info is None:
        log(f"{C.DIM}# {get_event_counter()} abs({abs_x1}, {abs_y1}) → abs({abs_x2}, {abs_y2})"
            f"  |  (KWin query failed){C.RESET}")
        return

    active_id    = kwin_info.get("active_id", "")
    win_x        = kwin_info.get("win_x", 0)
    win_y        = kwin_info.get("win_y", 0)
    caption      = kwin_info.get("caption", "")
    app_alias    = id_index.get(active_id, "") or active_id[:12] or "(unknown)"
    rel_x1       = abs_x1 - win_x
    rel_y1       = abs_y1 - win_y
    rel_x2       = abs_x2 - win_x
    rel_y2       = abs_y2 - win_y
    caption_part = f'  |  "{caption}"' if caption else ""

    log(f"{C.CYAN}# {get_event_counter()} {app_alias}{caption_part}  |  "
        f"abs({abs_x1}, {abs_y1}) → abs({abs_x2}, {abs_y2})  |  "
        f"rel({rel_x1}, {rel_y1}) → rel({rel_x2}, {rel_y2}){C.RESET}")

    if not no_dsl:
        log(f"{C.GREEN}{{WDRAG {rel_x1}, {rel_y1} to {rel_x2}, {rel_y2}}}{C.RESET}")
    log()


# ── Device discovery ──────────────────────────────────────────────────────────

def _input_diagnostics() -> None:
    import glob as _glob, stat as _stat
    log("\n  -- Input access diagnostics --", to_stderr=True)
    has_input_in_token = False
    has_input_in_group = False
    current_user = os.environ.get("USER", os.environ.get("LOGNAME", ""))
    script_path  = os.path.abspath(__file__)

    try:
        for line in Path("/proc/self/status").read_text().splitlines():
            if line.startswith("Groups:"):
                raw_gids = line.split(":", 1)[1].strip().split()
                gid_names: list[str] = []
                gid_to_name: dict = {}
                try:
                    for gl in Path("/etc/group").read_text().splitlines():
                        parts = gl.split(":")
                        if len(parts) >= 3:
                            gid_to_name[parts[2]] = parts[0]
                        if (len(parts) >= 4 and parts[0] == "input"
                                and current_user
                                and current_user in parts[3].split(",")):
                            has_input_in_group = True
                    for gid in raw_gids:
                        name = gid_to_name.get(gid, "")
                        if "input" in (name.lower(), gid):
                            has_input_in_token = True
                        gid_names.append(f"{name}({gid})" if name else gid)
                except Exception:
                    gid_names = raw_gids
                log(f"  Process groups (kernel token): {' '.join(gid_names) or '(none)'}",
                    to_stderr=True)
                log(f"  input group: {'PRESENT' if has_input_in_token else 'NOT PRESENT'} in kernel token",
                    to_stderr=True)
                break
    except Exception as exc:
        log(f"  Could not read /proc/self/status: {exc}", to_stderr=True)

    sample_paths = sorted(_glob.glob("/dev/input/event*"))
    if sample_paths:
        try:
            st = Path(sample_paths[0]).stat()
            mode = _stat.filemode(st.st_mode)
            import grp as _grp
            try:    grp_name = _grp.getgrgid(st.st_gid).gr_name
            except: grp_name = str(st.st_gid)
            log(f"  {sample_paths[0]}: mode={mode}  group={grp_name}({st.st_gid})",
                to_stderr=True)
        except Exception as exc:
            log(f"  Could not stat {sample_paths[0]}: {exc}", to_stderr=True)
    else:
        log("  No /dev/input/event* files found", to_stderr=True)

    try:
        ep = Path("/sys/fs/selinux/enforce")
        if ep.exists():
            state = "enforcing" if ep.read_text().strip() == "1" else "permissive"
            log(f"  SELinux: {state}", to_stderr=True)
        else:
            log("  SELinux: disabled or not mounted", to_stderr=True)
    except Exception as exc:
        log(f"  Could not read SELinux state: {exc}", to_stderr=True)

    if has_input_in_group and not has_input_in_token:
        log(
            f"\n  NOTE: '{current_user}' is listed in /etc/group for 'input'\n"
            f"  but the current login session does not have the group active.\n"
            f"  This is a known issue with some login managers (e.g. SDDM)\n"
            f"  on Tumbleweed.  Immediate workaround — run:\n\n"
            f"    sg input -c \"python3 {script_path}\"\n",
            to_stderr=True,
        )
    log(to_stderr=True)


def find_pointer_devices():
    try:
        import evdev
    except ImportError:
        raise ImportError(
            "python-evdev is not installed.\n"
            "Install it with:  pip install evdev --user"
        )
    import glob as _glob

    devices = []; perm_errors = []; other_errors = []; rejected = []

    evdev_paths = list(evdev.list_devices())
    if not evdev_paths:
        evdev_paths = sorted(_glob.glob("/dev/input/event*"))
    if not evdev_paths:
        return []

    for path in evdev_paths:
        try:
            dev  = evdev.InputDevice(path)
            caps = dev.capabilities()
            if EV_KEY in caps and BTN_LEFT in caps[EV_KEY]:
                devices.append(dev)
            elif EV_REL in caps:
                devices.append(dev)
            else:
                cap_types = sorted(caps.keys())
                cap_summary = ", ".join(
                    f"EV_{n}" for n in (
                        {0:"SYN",1:"KEY",2:"REL",3:"ABS",
                         4:"MSC",17:"LED",18:"SND",20:"REP",
                         21:"FF"}.get(k, str(k)) for k in cap_types))
                rejected.append((path, dev.name, cap_summary))
                dev.close()
        except PermissionError as exc: perm_errors.append((path, str(exc)))
        except Exception as exc:       other_errors.append((path, str(exc)))

    if devices:
        return devices

    if perm_errors:
        paths_shown = "\n".join(f"  {p}" for p, _ in perm_errors[:5])
        raise PermissionError(
            f"Cannot read {len(perm_errors)} input device(s) "
            f"(permission denied):\n{paths_shown}\n\n"
            "Options:\n\n"
            "  Option 1 — immediate workaround (user is in /etc/group\n"
            "  for 'input' but session token doesn't include it yet):\n"
            f"    sg input -c \"python3 {os.path.abspath(__file__)}\"\n\n"
            "  Option 2 — if not yet in the input group:\n"
            "    sudo usermod -aG input $USER\n"
            "    Then log out and back in, or reboot.\n\n"
            "  Option 3 — if usermod ran and you rebooted but the group\n"
            "  is still missing from the session (login manager issue):\n"
            "    Check your SDDM / PAM configuration, or use Option 1\n"
            "    as a permanent workaround via a shell alias or wrapper."
        )
    if rejected:
        lines = "\n".join(f"  {p}  [{name}]  caps: {caps}"
                          for p, name, caps in rejected)
        raise RuntimeError(
            f"Found {len(rejected)} input device(s) but none look like a "
            f"pointer (no BTN_LEFT or EV_REL):\n{lines}\n\n"
            "If your mouse is listed above, please report this as a bug."
        )
    if other_errors:
        lines = "\n".join(f"  {p}: {e}" for p, e in other_errors[:5])
        raise RuntimeError(f"Could not open any input device:\n{lines}")
    return []


# ── Main event loop ───────────────────────────────────────────────────────────

def monitor_loop(devices: list, kwin_mon: KWinMonitor,
                 id_index: dict[str, str],
                 no_dsl: bool, verbose: bool,
                 drag_threshold: int = 5) -> None:
    import queue, evdev

    event_queue: queue.Queue = queue.Queue()

    def reader(dev):
        tracker = PointerTracker()
        try:
            for event in dev.read_loop():
                event_queue.put((dev.name, tracker, event))
                tracker.feed(event.type, event.code, event.value)
        except Exception:
            pass

    for dev in devices:
        threading.Thread(target=reader, args=(dev,), daemon=True).start()

    log(f"{C.BOLD}{C.CYAN}Monitoring {len(devices)} device(s).  "
        f"Press Ctrl-C to stop.{C.RESET}\n")

    device_trackers: dict[str, PointerTracker] = {
        dev.name: PointerTracker() for dev in devices
    }
    kb_buffer       = KeyboardBuffer()
    last_active_id  = ""
    last_kwin_info: dict | None = None
    # State for deferred left-click / drag detection.
    # Set on BTN_LEFT press; cleared and logged on BTN_LEFT release.
    pending_left: dict | None = None

    try:
        while True:
            try:
                dev_name, tracker, event = event_queue.get(timeout=1.0)
            except queue.Empty:
                continue

            mt = device_trackers.setdefault(dev_name, PointerTracker())
            mt.feed(event.type, event.code, event.value)

            # ── Keyboard events ───────────────────────────────────────────
            if (event.type == EV_KEY
                    and event.code not in (BTN_LEFT, BTN_RIGHT, BTN_MIDDLE)):
                should_flush = kb_buffer.key_event(event.code, event.value)
                if should_flush:
                    kwin_info = kwin_mon.query_click()
                    if kwin_info:
                        last_kwin_info = kwin_info
                        last_active_id = kwin_info.get("active_id", "")
                    kb_buffer.flush(
                        kwin_info = last_kwin_info,
                        id_index  = id_index,
                        no_dsl    = no_dsl,
                    )

            # ── BTN_LEFT press — save state; log deferred to release ──────
            elif (event.type == EV_KEY and event.value == KEY_PRESSED
                  and event.code == BTN_LEFT):

                kwin_info = kwin_mon.query_click()
                if kwin_info:
                    mt.seed(kwin_info.get("cursor_x", 0),
                            kwin_info.get("cursor_y", 0))

                # Window change → flush keyboard buffer first
                new_active_id = (kwin_info or {}).get("active_id", "")
                if new_active_id and new_active_id != last_active_id:
                    if not kb_buffer.is_empty():
                        kb_buffer.flush(
                            kwin_info = last_kwin_info,
                            id_index  = id_index,
                            no_dsl    = no_dsl,
                        )
                    last_active_id = new_active_id

                if kwin_info:
                    last_kwin_info = kwin_info

                # Park press coords for drag/click decision on release
                pending_left = {
                    "abs_x":     mt.x,
                    "abs_y":     mt.y,
                    "kwin_info": kwin_info,
                }

            # ── BTN_LEFT release — decide click vs drag ───────────────────
            elif (event.type == EV_KEY and event.value == KEY_RELEASED
                  and event.code == BTN_LEFT):

                if pending_left is not None:
                    dx = abs(mt.x - pending_left["abs_x"])
                    dy = abs(mt.y - pending_left["abs_y"])
                    if dx <= drag_threshold and dy <= drag_threshold:
                        log_click(
                            button    = BTN_LEFT,
                            abs_x     = pending_left["abs_x"],
                            abs_y     = pending_left["abs_y"],
                            kwin_info = pending_left["kwin_info"],
                            id_index  = id_index,
                            no_dsl    = no_dsl,
                        )
                    else:
                        log_drag(
                            abs_x1    = pending_left["abs_x"],
                            abs_y1    = pending_left["abs_y"],
                            abs_x2    = mt.x,
                            abs_y2    = mt.y,
                            kwin_info = pending_left["kwin_info"],
                            id_index  = id_index,
                            no_dsl    = no_dsl,
                        )
                    pending_left = None

            # ── BTN_RIGHT / BTN_MIDDLE press — log immediately on press ───
            elif (event.type == EV_KEY and event.value == KEY_PRESSED
                  and event.code in (BTN_RIGHT, BTN_MIDDLE)):

                kwin_info = kwin_mon.query_click()
                if kwin_info:
                    mt.seed(kwin_info.get("cursor_x", 0),
                            kwin_info.get("cursor_y", 0))

                # Window change → flush keyboard buffer first
                new_active_id = (kwin_info or {}).get("active_id", "")
                if new_active_id and new_active_id != last_active_id:
                    if not kb_buffer.is_empty():
                        kb_buffer.flush(
                            kwin_info = last_kwin_info,
                            id_index  = id_index,
                            no_dsl    = no_dsl,
                        )
                    last_active_id = new_active_id

                if kwin_info:
                    last_kwin_info = kwin_info

                log_click(
                    button    = event.code,
                    abs_x     = mt.x,
                    abs_y     = mt.y,
                    kwin_info = kwin_info,
                    id_index  = id_index,
                    no_dsl    = no_dsl,
                )

            # ── Verbose mouse-move ────────────────────────────────────────
            elif verbose and event.type == EV_REL:
                log(f"{C.DIM}# move  abs({mt.x}, {mt.y}){C.RESET}")

    except KeyboardInterrupt:
        # Flush any pending left-button press as a click (button was held at exit)
        if pending_left is not None:
            log_click(
                button    = BTN_LEFT,
                abs_x     = pending_left["abs_x"],
                abs_y     = pending_left["abs_y"],
                kwin_info = pending_left["kwin_info"],
                id_index  = id_index,
                no_dsl    = no_dsl,
            )
        # Flush any pending keyboard input before exiting
        if not kb_buffer.is_empty():
            kb_buffer.flush(
                kwin_info = last_kwin_info,
                id_index  = id_index,
                no_dsl    = no_dsl,
            )
        log(f"\n{C.YELLOW}Stopped.{C.RESET}")


# ── Setup file resolution ─────────────────────────────────────────────────────

def resolve_setup_file(setup_arg: str | None, cfg) -> Path | None:
    if setup_arg:
        p = Path(setup_arg).expanduser()
        return p if p.exists() else None
    if not cfg.default_setup:
        return None
    filename   = cfg.default_setup
    config_dir = Path("~/.config/wayland-desktop").expanduser()
    for candidate in [Path(filename), config_dir / filename,
                      cfg.snapshot_dir / filename]:
        resolved = candidate.expanduser().resolve()
        if resolved.exists():
            return resolved
    return None


# ── Main ──────────────────────────────────────────────────────────────────────

def main() -> None:
    global _log_file

    parser = argparse.ArgumentParser(
        prog="kwin_mouse-clicks.py",
        description=(
            "Monitor mouse clicks and keyboard input; log as wayland-desktop "
            "input_actions DSL.\n"
            "Run in a Konsole session.  Output pastes directly into "
            "input_actions in a YAML setup file."
        ),
        formatter_class=argparse.RawDescriptionHelpFormatter,
    )
    parser.add_argument("--setup",       default="", metavar="FILE",
        help="Setup/snapshot YAML for known window names.")
    parser.add_argument("--config",      default="", metavar="FILE",
        help="Alternate wayland-desktop config file.")
    parser.add_argument("--log",         default="", metavar="FILE",
        help="Also write output to FILE (write mode, ANSI stripped).")
    parser.add_argument("--no-dsl",      action="store_true",
        help="Print comment lines only; suppress DSL token output.")
    parser.add_argument("--verbose",     action="store_true",
        help="Also log mouse-move events (very noisy).")
    parser.add_argument("--drag-threshold", type=int, default=5, metavar="N",
        help="Pixel displacement (either axis) to distinguish a drag from a click. "
             "Default: 5.")
    args = parser.parse_args()

    if args.log:
        try:
            _log_file = open(args.log, "w", encoding="utf-8")
        except OSError as exc:
            print(f"{C.RED}[ERROR] Cannot open log file {args.log!r}: "
                  f"{exc}{C.RESET}", file=sys.stderr)
            sys.exit(1)

    cfg           = load_config(args.config or None)
    session_state = SessionState.load()
    n_known       = len(session_state)

    snapshot: LayoutSnapshot | None = None
    snapshot_path = resolve_setup_file(args.setup or None, cfg)
    if snapshot_path:
        try:
            snapshot = LayoutSnapshot.load(snapshot_path)
        except Exception as exc:
            log(f"{C.YELLOW}[WARN ] Cannot load snapshot {snapshot_path}: "
                f"{exc}{C.RESET}", to_stderr=True)

    id_index = build_id_index(session_state, snapshot)

    log(f"{C.BOLD}wayland-desktop mouse click + keyboard monitor{C.RESET}")
    log(f"  Session state: {n_known} known window(s)")
    if snapshot_path:  log(f"  Setup file   : {snapshot_path}")
    if args.log:       log(f"  Log file     : {args.log}")
    if n_known == 0:
        log(f"\n{C.YELLOW}  Note: session state is empty — window names from "
            f"session state will not be available.\n"
            f"  Run kwin_restore.py first to populate window IDs.{C.RESET}")
    log()

    kwin_mon = KWinMonitor(verbose=args.verbose)
    try:
        kwin_mon.open()
    except RuntimeError as exc:
        log(f"{C.RED}[ERROR] Cannot connect to KWin: {exc}{C.RESET}",
            to_stderr=True)
        sys.exit(1)

    try:
        devices = find_pointer_devices()
    except ImportError as exc:
        log(f"{C.RED}[ERROR] {exc}{C.RESET}", to_stderr=True)
        kwin_mon.close(); sys.exit(1)
    except (PermissionError, RuntimeError) as exc:
        _input_diagnostics()
        log(f"{C.RED}[ERROR] {exc}{C.RESET}", to_stderr=True)
        kwin_mon.close(); sys.exit(1)

    if not devices:
        _input_diagnostics()
        log(f"{C.RED}[ERROR] No pointer devices found.{C.RESET}",
            to_stderr=True)
        kwin_mon.close(); sys.exit(1)

    log("  Devices found:")
    for dev in devices:
        log(f"    {dev.path}  —  {dev.name}")
    log()

    try:
        monitor_loop(
            devices=devices, kwin_mon=kwin_mon, id_index=id_index,
            no_dsl=args.no_dsl, verbose=args.verbose,
            drag_threshold=args.drag_threshold,
        )
    finally:
        for dev in devices:
            try: dev.close()
            except Exception: pass
        kwin_mon.close()
        if _log_file is not None:
            _log_file.close()


if __name__ == "__main__":
    main()
